INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('培训运营实习生 - 上海（实习）', '制造', '上海', '民营企业', 160, 240, '1. 熟练使用办公软件，熟悉飞书表格和文档使用者优先；2. 熟练使用PS/AI/剪映，有海报制作、宣传资料设计等经验者优先；3. 具备基础的培训运营与数据整理能力', '1. 具有较强的协调组织能力、沟通能力、分析能力、执行力及亲和力；2. 责任心强，语言和文字表达能力强；3. 善于反思与复盘，学习能力强', 1, '极度友好', '1. 参与培训整体流程，跟进基础培训运营工作，包括但不限于讲师协调、培训通知、线上直播课程运营等；2. 负责基础培训数据的整理工作，如学员信息、参与情况、签到数据、考试数据等；3. 负责培训物料的管理工作，做好月度盘点、出库、入库及登记等；4. 负责培训物料的设计工作和其他与培训运营相关的项目性工作', 'OD 组织发展支持', '本科及以上', '人力资源、管理等相关专业优先', '每周在岗5天，可实习6个月', '日常实习', '1. 有汽车行业培训运营相关经验；2. 有设计、视频剪辑相关作品', '200元/天', '46112', '46404', 'https://www.shixiseng.com/intern/inn_sdybqvwzqf2ae?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训实习生（生活服务方向） - 上海（实习）', '互联网 / IT', '上海', '民营企业', 200, 400, '1. 掌握使用Office三件套（PPT/Excel/Word），精通图表制作与排版设计优先；2. 掌握基础设计工具（如PS/AI/Canva），有作品集者优先；3. 可使用相机进行基础的视频拍摄和剪辑工作，熟练使用剪映&PR等视频剪辑工具', '1. 有表达&文字能力，能够编辑培训文案，梳理内容逻辑；2. 有独立思考能力，能够主动探索、发现问题并解决问题；3. 擅长通过表格工具提炼关键信息，有审美能力，能将专业知识转化为易懂、美观的视觉内容', 1, '极度友好', '1. 培训项目支持与执行，协助培训项目全流程管理，包括需求调研、项目执行、协助效果复盘；2. 独立完成小型项目模块，如培训材料整理、学员档案管理、满意度调研分析，熟练使用Excel等工具完成数据统计和报表制作；3. 平面设计&拍摄剪辑能力应用，设计并优化培训物料（如PPT课件、宣传海报等），提升内容吸引力；4. 学习平台维护，协助搭建和维护内部知识平台，整理标准化流程文档', 'OD 组织发展支持', '不限', '教育学、设计类、管理类相关专业优先', '可实习至少3个月，每周全勤工作5天，尽快入职的优先', '日常实习', '1. 有培训运营、课程设计相关经验；2. 有互联网大厂实习经验', '200-400元/天', '46109', '46125', 'https://www.shixiseng.com/intern/inn_jsvwlgyvn87?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('人力资源管培生（培训与发展方向） - 上海（校招）', '快消', '上海', '民营企业', 10000, 18000, '1. 英语听说读写流利，可作为工作语言；2. 熟练使用Office办公软件，可独立完成PPT、视频等学习材料制作；3. 具备基础的培训项目全流程运营能力', '1. 善于创新，对学习形式、培训玩法有好奇心，愿意尝试新工具、新设计；2. 对新技术，尤其对AI敏感度高，乐于探索并应用新工具；3. 主观能动性强，主动发现问题、主动优化流程；4. 结果导向，抗压能力强，具备优秀的执行力、统筹协调能力、情绪管理能力、团队协作能力', 1, '友好', '1. 协助培训项目的组织运营，包括需求调研、课程安排、物料准备、现场支持、效果评估；2. 参与培训课程内容的优化与学习材料的制作（PPT、视频、手册等）；3. 支持线上学习平台的日常运营与内容更新；4. 独立承担小型培训项目运营，积累学习项目设计与交付的完整经验', 'OD 组织发展支持', '本科及以上', '人力资源、英语等相关专业优先，跨界复合背景更佳', '2026届应届生', '应届生校招', '1. 有教学设计、课程开发、培训助理或社团培训类经验者优先；2. 有AI工具应用、课程设计相关经验', '10k-18k/月', '46112', '46186', 'https://www.shixiseng.com/intern/inn_ya1g6cqdtpm?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训助理 - 北京（校招）', '医疗健康 / 生物', '北京', '民营企业', 6000, 8000, '1. 熟练使用Office办公软件，具备基础的数据统计与分析能力；2. 具备基础的会议筹备与现场执行能力；3. 具备良好的应急处理能力', '1. 组织协调能力强，工作严谨；2. 有较强的抗压能力；3. 工作认真负责，执行力强', 1, '友好', '1. 负责培训会议物料的申请、管理；2. 负责培训会议数据汇总、分析；3. 负责培训会议档案的建立与维护；4. 负责培训会议资料的保存与备份；5. 负责培训会议会场的布置；6. 负责培训会议开始前的宣导；7. 负责培训会议过程中的突发问题解决', 'OD 组织发展支持', '大专及以上', '人力资源或表演等专业优先', '毕业1年内的应届生', '应届生校招', '1. 有培训助理、会议执行相关经验；2. 有美业、大健康行业相关经验', '6k-8k/月', '45823', '46112', 'https://www.shixiseng.com/intern/inn_plszrvnwe0?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训专员 - 杭州（校招）', '互联网 / IT', '杭州', '民营企业', 5000, 10000, '1. 具备AI应用搭建能力，可完成智能体、自动化工具等搭建；2. 具备基础的课件制作、内容整理能力；3. 熟练使用Office办公软件', '1. 对AI技术有浓厚兴趣，学习能力强；2. 具备良好的逻辑思维能力，可快速上手新工具；3. 具备良好的公开表达能力和团队协作精神', 1, '极度友好', '1. 协助AI课程开发：在导师指导下，参与AI培训课程的内容搜集、案例整理和课件制作；2. 技术应用搭建：动手搭建AI应用（如智能体、自动化工具等），并将其转化为教学案例或演示Demo；3. 项目支持：协助咨询项目进行技术测试、资料准备及项目落地的辅助工作；4. 技术追踪：关注AI领域的最新工具和技术，进行主题分享、试用和评测', 'OD 组织发展支持', '本科及以上', '计算机、人工智能或相关专业', '2027届在校生，有AI应用搭建经验者优先', '应届生校招', '有AI应用搭建、课程开发相关经验者优先', '薪资面议', '46099', '46464', 'https://www.shixiseng.com/intern/inn_ji5c64xwiax?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）');